  1→// ABOUTME: Dashboard client — fetches session data, renders UI, handles interactions.
  2→// ABOUTME: Vanilla JS with no build step; polls /api/sessions for updates.
  3→
  4→(function () {
  5→  "use strict";
  6→
  7→  // --- State ---
  8→  let dashboardData = null;
  9→  let lastScannedTime = null;
 10→  let expandedRepos = new Set(); // repo_root values that are expanded
 11→  var timeFilterDays = Infinity; // max days back to show (Infinity = all)
 12→
 13→  // --- DOM refs ---
 14→  const $loading = document.getElementById("loading");
 15→  const $repoGroups = document.getElementById("repo-groups");
 16→  const $nonRepoGroups = document.getElementById("non-repo-groups");
 17→  const $chronoView = document.getElementById("chrono-view");
 18→  const $emptyState = document.getElementById("empty-state");
 19→  const $lastScan = document.getElementById("last-scan");
 20→  const $btnRefresh = document.getElementById("btn-refresh");
 21→  const $scanDays = document.getElementById("scan-days");
 22→  const $timeSlider = document.getElementById("time-slider");
 23→  const $timeSliderLabel = document.getElementById("time-slider-label");
 24→  const $searchOverlay = document.getElementById("search-overlay");
 25→  const $searchInput = document.getElementById("search-input");
 26→  const $searchResults = document.getElementById("search-results");
 27→
 28→  // --- Helpers ---
 29→
 30→  function timeAgo(isoString) {
 31→    if (!isoString) return "--";
 32→    const diff = Date.now() - new Date(isoString).getTime();
 33→    const seconds = Math.floor(diff / 1000);
 34→    if (seconds < 60) return seconds + "s ago";
 35→    const minutes = Math.floor(seconds / 60);
 36→    if (minutes < 60) return minutes + "m ago";
 37→    const hours = Math.floor(minutes / 60);
 38→    if (hours < 24) return hours + "h ago";
 39→    const days = Math.floor(hours / 24);
 40→    return days + "d ago";
 41→  }
 42→
 43→  function statusCssClass(status) {
 44→    return (status || "").replace(/\s+/g, "-");
 45→  }
 46→
 47→  function isActiveDot(status) {
 48→    return ["in progress", "likely in progress", "waiting for input"].includes(status);
 49→  }
 50→
 51→  var INITIAL_VISIBLE = 10;
 52→
 53→  function escapeHtml(str) {
 54→    const div = document.createElement("div");
 55→    div.textContent = str || "";
 56→    return div.innerHTML;
 57→  }
 58→
 59→  function sessionLabel(session) {
 60→    if (session.summary) return session.summary;
 61→    if (session.slug) return session.slug;
 62→    return session.id.substring(0, 8) + "\u2026";
 63→  }
 64→
 65→  function allSessions() {
 66→    if (!dashboardData) return [];
 67→    var sessions = [];
 68→    (dashboardData.repo_groups || []).forEach(function (g) {
 69→      g.sessions.forEach(function (s) {
 70→        sessions.push({ session: s, repoName: g.repo_name || "" });
 71→      });
 72→    });
 73→    (dashboardData.non_repo_groups || []).forEach(function (g) {
 74→      var name = g.cwd.split("/").filter(Boolean).pop() || g.cwd;
 75→      g.sessions.forEach(function (s) {
 76→        sessions.push({ session: s, repoName: name });
 77→      });
 78→    });
 79→    return sessions;
 80→  }
 81→
 82→  function fuzzyMatch(text, query) {
 83→    var tLower = text.toLowerCase();
 84→    var qLower = query.toLowerCase();
 85→    var qi = 0;
 86→    var indices = [];
 87→    for (var ti = 0; ti < tLower.length && qi < qLower.length; ti++) {
 88→      if (tLower[ti] === qLower[qi]) {
 89→        indices.push(ti);
 90→        qi++;
 91→      }
 92→    }
 93→    if (qi < qLower.length) return null;
 94→    // Score: prefer consecutive matches and matches at word boundaries
 95→    var score = 0;
 96→    for (var i = 0; i < indices.length; i++) {
 97→      if (i > 0 && indices[i] === indices[i - 1] + 1) score += 10;
 98→      if (indices[i] === 0 || text[indices[i] - 1] === " ") score += 5;
 99→    }
100→    return { indices: indices, score: score };
101→  }
102→
103→  function highlightMatches(text, indices) {
104→    if (!indices || indices.length === 0) return escapeHtml(text);
105→    var result = "";
106→    var idxSet = new Set(indices);
107→    var inMark = false;
108→    for (var i = 0; i < text.length; i++) {
109→      if (idxSet.has(i) && !inMark) {
110→        result += "<mark>";
111→        inMark = true;
112→      } else if (!idxSet.has(i) && inMark) {
113→        result += "</mark>";
114→        inMark = false;
115→      }
116→      result += escapeHtml(text[i]);
117→    }
118→    if (inMark) result += "</mark>";
119→    return result;
120→  }
121→
122→  function parsePhaseDate(phase) {
123→    // Use start_date (ISO) if available, otherwise parse the period string
124→    if (phase.start_date) {
125→      return new Date(phase.start_date + "T00:00:00").getTime();
126→    }
127→    var period = phase.period || "";
128→    var now = new Date();
129→    if (period === "Today") return new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
130→    if (period === "Yesterday") return new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1).getTime();
131→    // Parse "Mar 17" or "Mar 10-12" (use first date in range)
132→    var months = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
133→    var m = period.match(/^([A-Z][a-z]{2})\s+(\d+)/);
134→    if (m && months[m[1]] !== undefined) {
135→      var year = now.getFullYear();
136→      var d = new Date(year, months[m[1]], parseInt(m[2], 10));
137→      // If the parsed date is in the future, it's from last year
138→      if (d.getTime() > now.getTime() + 86400000) d.setFullYear(year - 1);
139→      return d.getTime();
140→    }
141→    return 0; // can't parse — don't filter
142→  }
143→
144→  function filterSessionByTime(session) {
145→    if (timeFilterDays === Infinity) return true;
146→    if (!session.last_active) return false;
147→    var cutoff = Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
148→    return new Date(session.last_active).getTime() >= cutoff;
149→  }
150→
151→  function filterGroupSessions(group) {
152→    return group.sessions.filter(filterSessionByTime);
153→  }
154→
155→  // --- Rendering ---
156→
157→  function renderSessionRow(session) {
158→    const cssCls = statusCssClass(session.status);
159→    const row = document.createElement("div");
160→    row.className = "session-row";
161→    row.innerHTML =
162→      '<div class="status-dot ' + cssCls + '"></div>' +
163→      '<div class="session-summary">' + escapeHtml(sessionLabel(session)) + "</div>" +
164→      '<span class="status-label ' + cssCls + '">' + escapeHtml(session.status) + "</span>" +
165→      '<span class="time-ago">' + timeAgo(session.last_active) + "</span>" +
166→      '<span class="source-badge ' + session.source + '">' + session.source + "</span>";
167→
168→    row.addEventListener("click", function () {
169→      launchSession(session, row);
170→    });
171→
172→    return row;
173→  }
174→
175→  // Octocat SVG icon for git repo groups
176→  var OCTOCAT_SVG = '<svg class="octocat-icon" viewBox="0 0 16 16" width="14" height="14" fill="currentColor">' +
177→    '<path d="M8 0C3.58 0 0 3.58 0 8c0 3.54 2.29 6.53 5.47 7.59.4.07.55-.17.55-.38 0-.19-.01-.82-.01-1.49' +
178→    '-2.01.37-2.53-.49-2.69-.94-.09-.23-.48-.94-.82-1.13-.28-.15-.68-.52-.01-.53.63-.01 1.08.58 1.23.82' +
179→    '.72 1.21 1.87.87 2.33.66.07-.52.28-.87.51-1.07-1.78-.2-3.64-.89-3.64-3.95 0-.87.31-1.59.82-2.15' +
180→    '-.08-.2-.36-1.02.08-2.12 0 0 .67-.21 2.2.82.64-.18 1.32-.27 2-.27.68 0 1.36.09 2 .27 1.53-1.04 2.2-.82' +
181→    ' 2.2-.82.44 1.1.16 1.92.08 2.12.51.56.82 1.27.82 2.15 0 3.07-1.87 3.75-3.65 3.95.29.25.54.73.54 1.48' +
182→    ' 0 1.07-.01 1.93-.01 2.2 0 .21.15.46.55.38A8.013 8.013 0 0016 8c0-4.42-3.58-8-8-8z"/></svg>';
183→
184→  function buildGroupHeaderHtml(opts, isExpanded, sessionCount) {
185→    var chevron = '<span class="repo-chevron ' + (isExpanded ? "expanded" : "") + '" aria-hidden="true">\u25B6</span>';
186→    var icon = opts.icon || "";
187→    var name = '<span class="repo-name">' + escapeHtml(opts.displayName) + "</span>";
188→    var meta = '<span class="repo-meta">(' + opts.metaText + ")</span>";
189→    var btn = '<button class="btn-new-session" title="New Claude session in ' + escapeHtml(opts.cwd) + '" aria-label="New session in ' + escapeHtml(opts.displayName) + '">+</button>';
190→
191→    return (
192→      '<div class="repo-header-left">' + chevron + icon + name + meta + "</div>" +
193→      '<div class="repo-header-right">' + btn + timeAgo(opts.lastActive) + "</div>"
194→    );
195→  }
196→
197→  function renderGroup(opts, filteredSessions) {
198→    if (filteredSessions.length === 0) return null;
199→
200→    var groupKey = opts.groupKey;
201→    var isExpanded = expandedRepos.has(groupKey);
202→    var container = document.createElement("div");
203→    container.className = "repo-group";
204→
205→    var header = document.createElement("div");
206→    header.className = "repo-header";
207→    header.setAttribute("role", "button");
208→    header.setAttribute("aria-expanded", isExpanded ? "true" : "false");
209→    header.setAttribute("tabindex", "0");
210→    header.innerHTML = buildGroupHeaderHtml(opts, isExpanded, filteredSessions.length);
211→
212→    var sessionList = document.createElement("div");
213→    sessionList.className = "session-list" + (isExpanded ? "" : " collapsed");
214→
215→    // Render timeline if present, filtered by time slider
216→    if (opts.timeline && opts.timeline.length > 0) {
217→      var timelineEl = document.createElement("div");
218→      timelineEl.className = "repo-timeline";
219→      var cutoff = timeFilterDays === Infinity ? 0 : Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
220→      opts.timeline.forEach(function (phase) {
221→        if (cutoff > 0) {
222→          var phaseTime = parsePhaseDate(phase);
223→          if (phaseTime > 0 && phaseTime < cutoff) return;
224→        }
225→        var phaseEl = document.createElement("div");
226→        phaseEl.className = "timeline-phase";
227→        phaseEl.innerHTML =
228→          '<span class="timeline-period">' + escapeHtml(phase.period) + '</span>' +
229→          '<span class="timeline-desc">' + escapeHtml(phase.description) + '</span>';
230→        timelineEl.appendChild(phaseEl);
231→      });
232→      if (timelineEl.children.length > 0) {
233→        sessionList.appendChild(timelineEl);
234→      }
235→    }
236→
237→    var showingAll = filteredSessions.length <= INITIAL_VISIBLE;
238→
239→    function renderVisibleSessions() {
240→      var timeline = sessionList.querySelector(".repo-timeline");
241→      sessionList.innerHTML = "";
242→      if (timeline) sessionList.appendChild(timeline);
243→
244→      var toShow = showingAll ? filteredSessions : filteredSessions.slice(0, INITIAL_VISIBLE);
245→      toShow.forEach(function (session) {
246→        sessionList.appendChild(renderSessionRow(session));
247→      });
248→      if (!showingAll) {
249→        var moreBtn = document.createElement("div");
250→        moreBtn.className = "show-more-btn";
251→        moreBtn.textContent = "Show all " + filteredSessions.length + " sessions";
252→        moreBtn.addEventListener("click", function (e) {
253→          e.stopPropagation();
254→          showingAll = true;
255→          renderVisibleSessions();
256→          sessionList.style.maxHeight = sessionList.scrollHeight + "px";
257→        });
258→        sessionList.appendChild(moreBtn);
259→      }
260→    }
261→    renderVisibleSessions();
262→
263→    header.querySelector(".btn-new-session").addEventListener("click", function (e) {
264→      e.stopPropagation();
265→      openNewSession(opts.cwd);
266→    });
267→
268→    header.addEventListener("click", function () {
269→      if (expandedRepos.has(groupKey)) {
270→        expandedRepos.delete(groupKey);
271→        sessionList.classList.add("collapsed");
272→        header.querySelector(".repo-chevron").classList.remove("expanded");
273→        header.setAttribute("aria-expanded", "false");
274→      } else {
275→        expandedRepos.add(groupKey);
276→        sessionList.classList.remove("collapsed");
277→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
278→        header.querySelector(".repo-chevron").classList.add("expanded");
279→        header.setAttribute("aria-expanded", "true");
280→      }
281→    });
282→
283→    if (isExpanded) {
284→      requestAnimationFrame(function () {
285→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
286→      });
287→    }
288→
289→    container.appendChild(header);
290→    container.appendChild(sessionList);
291→    return container;
292→  }
293→
294→  function renderRepoGroup(group, filteredSessions) {
295→    var metaParts = [];
296→    if (group.git_branch) metaParts.push(group.git_branch);
297→    if (group.git_dirty) metaParts.push('<span class="dirty">dirty</span>');
298→    if (group.unpushed_commits > 0) metaParts.push('<span class="unpushed">' + group.unpushed_commits + " unpushed</span>");
299→    if (!group.git_dirty && group.unpushed_commits === 0) metaParts.push("clean");
300→    metaParts.push(filteredSessions.length + " sessions");
301→
302→    return renderGroup({
303→      groupKey: group.repo_root,
304→      displayName: group.repo_name,
305→      icon: OCTOCAT_SVG,
306→      metaText: metaParts.join(", "),
307→      cwd: group.repo_root,
308→      lastActive: group.last_active,
309→      timeline: group.timeline,
310→    }, filteredSessions);
311→  }
312→
313→  function renderNonRepoGroup(group, filteredSessions) {
314→    var displayName = group.cwd.split("/").filter(Boolean).pop() || group.cwd;
315→
316→    return renderGroup({
317→      groupKey: group.cwd,
318→      displayName: displayName,
319→      icon: "",
320→      metaText: filteredSessions.length + " sessions",
321→      cwd: group.cwd,
322→      lastActive: group.last_active,
323→      timeline: group.timeline,
324→    }, filteredSessions);
325→  }
326→
327→  function render() {
328→    if (!dashboardData) return;
329→
330→    $loading.classList.add("hidden");
331→
332→    var hasRepos = (dashboardData.repo_groups || []).length > 0;
333→    var hasNonRepos = (dashboardData.non_repo_groups || []).length > 0;
334→
335→    if (!hasRepos && !hasNonRepos) {
336→      $emptyState.classList.remove("hidden");
337→      $repoGroups.classList.add("hidden");
338→      $nonRepoGroups.classList.add("hidden");
339→      $chronoView.classList.add("hidden");
340→      return;
341→    }
342→
343→    $emptyState.classList.add("hidden");
344→    $chronoView.classList.add("hidden");
345→    $repoGroups.classList.remove("hidden");
346→    $nonRepoGroups.classList.add("hidden");
347→
348→    // Combine repo and non-repo groups into one list sorted by last_active
349→    var allGroups = [];
350→    (dashboardData.repo_groups || []).forEach(function (g) {
351→      allGroups.push({ type: "repo", group: g, last_active: g.last_active });
352→    });
353→    (dashboardData.non_repo_groups || []).forEach(function (g) {
354→      allGroups.push({ type: "non-repo", group: g, last_active: g.last_active });
355→    });
356→    allGroups.sort(function (a, b) {
357→      return new Date(b.last_active) - new Date(a.last_active);
358→    });
359→
360→    // Auto-expand the first group on initial render
361→    if (expandedRepos.size === 0 && allGroups.length > 0) {
362→      var firstGroup = allGroups[0];
363→      var expandKey = firstGroup.type === "repo" ? firstGroup.group.repo_root : firstGroup.group.cwd;
364→      expandedRepos.add(expandKey);
365→    }
366→
367→    $repoGroups.innerHTML = "";
368→    allGroups.forEach(function (entry) {
369→      var filtered = filterGroupSessions(entry.group);
370→      var el = entry.type === "repo"
371→        ? renderRepoGroup(entry.group, filtered)
372→        : renderNonRepoGroup(entry.group, filtered);
373→      if (el) $repoGroups.appendChild(el);
374→    });
375→  }
376→
377→  // --- API ---
378→
379→  function fetchSessions() {
380→    return fetch("/api/sessions")
381→      .then(function (res) { return res.json(); })
382→      .then(function (data) {
383→        dashboardData = data;
384→        lastScannedTime = data.last_scanned;
385→        updateSliderRange();
386→        render();
387→        updateLastScan();
388→      })
389→      .catch(function (err) {
390→        console.error("Failed to fetch sessions:", err);
391→      });
392→  }
393→
394→  function refreshSessions() {
395→    var days = parseInt($scanDays.value, 10) || 7;
396→    $btnRefresh.classList.add("spinning");
397→    $btnRefresh.textContent = "Refreshing...";
398→    return fetch("/api/refresh?scan_days=" + days)
399→      .then(function (res) { return res.json(); })
400→      .then(function (data) {
401→        dashboardData = data;
402→        lastScannedTime = data.last_scanned;
403→        updateSliderRange();
404→        render();
405→        updateLastScan();
406→      })
407→      .catch(function (err) {
408→        console.error("Failed to refresh:", err);
409→      })
410→      .finally(function () {
411→        $btnRefresh.classList.remove("spinning");
412→        $btnRefresh.textContent = "Refresh";
413→      });
414→  }
415→
416→  function launchSession(session, rowEl) {
417→    rowEl.classList.add("launched");
418→    setTimeout(function () { rowEl.classList.remove("launched"); }, 500);
419→    openTerminal(session);
420→  }
421→
422→  // --- Terminal Tabs ---
423→
424→  var terminals = {};       // tabId → tabData
425→  var activeTabId = null;
426→  var tabIdCounter = 0;
427→  var resizeListenerAttached = false;
428→
429→  var $terminalPanel = document.getElementById("terminal-panel");
430→  var $terminalContainer = document.getElementById("terminal-container");
431→  var $terminalTabs = document.getElementById("terminal-tabs");
432→  var $terminalClose = document.getElementById("terminal-close");
433→
434→  function generateTabId() {
435→    return "tab-" + (tabIdCounter++);
436→  }
437→
438→  function renderTabs() {
439→    $terminalTabs.innerHTML = "";
440→    var ids = Object.keys(terminals);
441→    ids.forEach(function (tabId) {
442→      var tab = terminals[tabId];
443→      var el = document.createElement("div");
444→      el.className = "terminal-tab" + (tabId === activeTabId ? " active" : "") + (tab.ended ? " ended" : "");
445→      el.innerHTML =
446→        '<span class="terminal-tab-title">' + escapeHtml(tab.title) + '</span>' +
447→        '<span class="terminal-tab-close">&times;</span>';
448→
449→      el.querySelector(".terminal-tab-title").addEventListener("click", function () {
450→        switchTab(tabId);
451→      });
452→      el.querySelector(".terminal-tab-close").addEventListener("click", function (e) {
453→        e.stopPropagation();
454→        closeTab(tabId);
455→      });
456→
457→      $terminalTabs.appendChild(el);
458→    });
459→  }
460→
461→  function switchTab(tabId) {
462→    if (!terminals[tabId]) return;
463→    if (activeTabId && terminals[activeTabId]) {
464→      terminals[activeTabId].container.classList.remove("active");
465→    }
466→    activeTabId = tabId;
467→    terminals[tabId].container.classList.add("active");
468→    terminals[tabId].fitAddon.fit();
469→    terminals[tabId].term.focus();
470→    renderTabs();
471→  }
472→
473→  function closeTab(tabId) {
474→    var tab = terminals[tabId];
475→    if (!tab) return;
476→    tab.ws.close();
477→    tab.term.dispose();
478→    tab.container.remove();
479→    delete terminals[tabId];
480→
481→    if (activeTabId === tabId) {
482→      var remaining = Object.keys(terminals);
483→      if (remaining.length > 0) {
484→        switchTab(remaining[remaining.length - 1]);
485→      } else {
486→        activeTabId = null;
487→        $terminalPanel.classList.add("hidden");
488→        document.body.classList.remove("terminal-open");
489→        window.removeEventListener("resize", handleTerminalResize);
490→        resizeListenerAttached = false;
491→      }
492→    }
493→    renderTabs();
494→  }
495→
496→  function createTerminalTab(title, wsParams, sessionId) {
497→    var tabId = generateTabId();
498→
499→    var container = document.createElement("div");
500→    container.className = "terminal-tab-container";
501→    $terminalContainer.appendChild(container);
502→
503→    var term = new Terminal({
504→      fontFamily: '"JetBrains Mono", "SF Mono", monospace',
505→      fontSize: 13,
506→      theme: {
507→        background: "#111111",
508→        foreground: "#FAFAFA",
509→        cursor: "#FF4D00",
510→      },
511→      cursorBlink: true,
512→    });
513→
514→    var fitAddon = new FitAddon.FitAddon();
515→    term.loadAddon(fitAddon);
516→    term.loadAddon(new WebLinksAddon.WebLinksAddon());
517→
518→    term.open(container);
519→
520→    var tabData = {
521→      id: tabId,
522→      term: term,
523→      ws: null,
524→      fitAddon: fitAddon,
525→      container: container,
526→      title: title,
527→      ended: false,
528→      sessionId: sessionId,
529→    };
530→    terminals[tabId] = tabData;
531→
532→    $terminalPanel.classList.remove("hidden");
533→    document.body.classList.add("terminal-open");
534→
535→    // Hide previous active tab, show this one
536→    if (activeTabId && terminals[activeTabId]) {
537→      terminals[activeTabId].container.classList.remove("active");
538→    }
539→    activeTabId = tabId;
540→    container.classList.add("active");
541→    fitAddon.fit();
542→
543→    var params = new URLSearchParams(wsParams);
544→    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
545→    var wsUrl = wsProtocol + "//" + location.host + "/ws/terminal?" + params.toString();
546→    var ws = new WebSocket(wsUrl);
547→    tabData.ws = ws;
548→
549→    ws.onopen = function () {
550→      ws.send(JSON.stringify({ type: "resize", cols: term.cols, rows: term.rows }));
551→      term.focus();
552→    };
553→
554→    ws.onmessage = function (evt) {
555→      term.write(evt.data);
556→    };
557→
558→    ws.onclose = function () {
559→      term.write("\r\n\x1b[90m[session ended]\x1b[0m\r\n");
560→      tabData.ended = true;
561→      renderTabs();
562→    };
563→
564→    term.onData(function (data) {
565→      if (ws.readyState === WebSocket.OPEN) ws.send(data);
566→    });
567→
568→    term.onResize(function (size) {
569→      if (ws.readyState === WebSocket.OPEN) {
570→        ws.send(JSON.stringify({ type: "resize", cols: size.cols, rows: size.rows }));
571→      }
572→    });
573→
574→    if (!resizeListenerAttached) {
575→      window.addEventListener("resize", handleTerminalResize);
576→      resizeListenerAttached = true;
577→    }
578→
579→    renderTabs();
580→    return tabId;
