624→  function computeMaxDays() {
625→    if (!dashboardData) return 60;
626→    var oldest = Infinity;
627→    var all = allSessions();
628→    all.forEach(function (entry) {
629→      if (entry.session.last_active) {
630→        var t = new Date(entry.session.last_active).getTime();
631→        if (t < oldest) oldest = t;
632→      }
633→    });
634→    if (oldest === Infinity) return 60;
635→    return Math.max(1, Math.ceil((Date.now() - oldest) / (24 * 60 * 60 * 1000)));
636→  }
