668→  // --- Search Overlay ---
669→
670→  var searchSelectedIdx = 0;
671→  var searchMatches = [];
672→  var previouslyFocusedElement = null;
673→
674→  function openSearch() {
675→    previouslyFocusedElement = document.activeElement;
676→    $searchOverlay.classList.remove("hidden");
677→    $searchInput.value = "";
678→    $searchResults.innerHTML = "";
679→    searchSelectedIdx = 0;
680→    searchMatches = [];
681→    $searchInput.focus();
682→  }
683→
684→  function closeSearch() {
685→    $searchOverlay.classList.add("hidden");
686→    $searchInput.value = "";
687→    $searchResults.innerHTML = "";
688→    if (previouslyFocusedElement && previouslyFocusedElement.focus) {
689→      previouslyFocusedElement.focus();
690→    }
691→    previouslyFocusedElement = null;
692→  }
693→
694→  function performSearch(query) {
695→    $searchResults.innerHTML = "";
696→    searchSelectedIdx = 0;
697→
698→    if (!query.trim()) {
699→      searchMatches = [];
700→      return;
701→    }
702→
703→    var all = allSessions();
704→    var scored = [];
705→    all.forEach(function (entry) {
706→      var label = sessionLabel(entry.session);
707→      var searchText = label + " " + entry.repoName + " " + (entry.session.status || "");
708→      var m = fuzzyMatch(searchText, query);
709→      if (m) {
710→        // Re-match just the label for highlighting
711→        var labelMatch = fuzzyMatch(label, query);
712→        scored.push({
713→          session: entry.session,
714→          repoName: entry.repoName,
715→          score: m.score,
716→          labelIndices: labelMatch ? labelMatch.indices : [],
717→        });
718→      }
719→    });
720→
721→    scored.sort(function (a, b) { return b.score - a.score; });
722→    searchMatches = scored.slice(0, 50);
723→
724→    if (searchMatches.length === 0) {
725→      $searchResults.innerHTML = '<div class="search-no-results">No matches</div>';
726→      return;
727→    }
728→
729→    searchMatches.forEach(function (match, idx) {
730→      var row = document.createElement("div");
731→      row.className = "search-result-row" + (idx === 0 ? " selected" : "");
732→      var cssCls = statusCssClass(match.session.status);
733→      row.innerHTML =
734→        '<div class="status-dot ' + cssCls + '"></div>' +
735→        '<div>' +
736→          '<div class="search-result-summary">' +
737→            highlightMatches(sessionLabel(match.session), match.labelIndices) +
738→          '</div>' +
739→          '<span class="search-result-repo">' + escapeHtml(match.repoName) + '</span>' +
740→        '</div>' +
741→        '<span class="status-label ' + cssCls + '">' +
742→          escapeHtml(match.session.status) + '</span>' +
743→        '<span class="time-ago">' + timeAgo(match.session.last_active) + '</span>';
744→
745→      row.addEventListener("click", function () {
746→        closeSearch();
747→        launchFromSearch(match.session);
748→      });
749→      $searchResults.appendChild(row);
750→    });
751→  }
752→
753→  function launchFromSearch(session) {
754→    openTerminal(session);
755→  }
756→
757→  function updateSearchSelection() {
758→    var rows = $searchResults.querySelectorAll(".search-result-row");
759→    rows.forEach(function (r, i) {
760→      r.classList.toggle("selected", i === searchSelectedIdx);
761→    });
762→    if (rows[searchSelectedIdx]) {
763→      rows[searchSelectedIdx].scrollIntoView({ block: "nearest" });
764→    }
765→  }
766→
767→  $searchInput.addEventListener("input", function () {
768→    performSearch($searchInput.value);
769→  });
770→
771→  $searchInput.addEventListener("keydown", function (e) {
772→    if (e.key === "Escape") {
773→      e.preventDefault();
774→      closeSearch();
775→    } else if (e.key === "ArrowDown") {
776→      e.preventDefault();
777→      if (searchMatches.length > 0) {
778→        searchSelectedIdx = Math.min(searchSelectedIdx + 1, searchMatches.length - 1);
779→        updateSearchSelection();
780→      }
781→    } else if (e.key === "ArrowUp") {
782→      e.preventDefault();
783→      if (searchMatches.length > 0) {
784→        searchSelectedIdx = Math.max(searchSelectedIdx - 1, 0);
785→        updateSearchSelection();
786→      }
787→    } else if (e.key === "Enter") {
788→      e.preventDefault();
789→      if (searchMatches.length > 0 && searchMatches[searchSelectedIdx]) {
790→        closeSearch();
791→        launchFromSearch(searchMatches[searchSelectedIdx].session);
792→      }
793→    }
794→  });
795→
796→  $searchOverlay.addEventListener("click", function (e) {
797→    if (e.target === $searchOverlay) closeSearch();
798→  });
