816→  // --- Group Navigation (j/k) ---
817→
818→  var focusedGroupIdx = -1;
819→
820→  function getAllGroupElements() {
821→    return Array.from($repoGroups.querySelectorAll(".repo-group"));
822→  }
823→
824→  function setGroupFocus(idx) {
825→    var groups = getAllGroupElements();
826→    // Clear previous focus
827→    groups.forEach(function (el) {
828→      el.classList.remove("group-focused");
829→    });
830→    if (idx < 0 || idx >= groups.length) {
831→      focusedGroupIdx = -1;
832→      return;
833→    }
834→    focusedGroupIdx = idx;
835→    groups[idx].classList.add("group-focused");
836→    groups[idx].scrollIntoView({ block: "nearest", behavior: "smooth" });
837→  }
838→
839→  function toggleFocusedGroup() {
840→    var groups = getAllGroupElements();
841→    if (focusedGroupIdx < 0 || focusedGroupIdx >= groups.length) return;
842→    var header = groups[focusedGroupIdx].querySelector(".repo-header");
843→    if (header) header.click();
844→  }
845→
846→  // --- Global Keyboard Handler ---
847→
848→  document.addEventListener("keydown", function (e) {
849→    // Don't trigger if typing in an input or textarea
850→    if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
851→
852→    // Help overlay takes priority for close
853→    if (!$helpOverlay.classList.contains("hidden")) {
854→      if (e.key === "Escape" || e.key === "?") {
855→        e.preventDefault();
856→        closeHelp();
857→      }
858→      return;
859→    }
860→
861→    // Escape closes active terminal tab (returns focus to dashboard)
862→    if (e.key === "Escape" && activeTabId) {
863→      e.preventDefault();
864→      closeTab(activeTabId);
865→      return;
866→    }
867→
868→    // When terminal is focused, only Escape works (handled above)
869→    if (activeTabId) return;
870→
871→    if (e.key === "/") {
872→      e.preventDefault();
873→      openSearch();
874→    } else if (e.key === "?") {
875→      e.preventDefault();
876→      openHelp();
877→    } else if (e.key === "r") {
878→      e.preventDefault();
879→      refreshSessions();
880→    } else if (e.key === "j") {
881→      e.preventDefault();
882→      var groups = getAllGroupElements();
883→      if (groups.length > 0) {
884→        setGroupFocus(Math.min(focusedGroupIdx + 1, groups.length - 1));
885→      }
886→    } else if (e.key === "k") {
887→      e.preventDefault();
888→      if (focusedGroupIdx > 0) {
889→        setGroupFocus(focusedGroupIdx - 1);
890→      }
891→    } else if (e.key === "Enter" && focusedGroupIdx >= 0) {
892→      e.preventDefault();
893→      toggleFocusedGroup();
894→    }
895→  });
896→
897→  // --- Event listeners ---
898→
899→  $btnRefresh.addEventListener("click", refreshSessions);
900→
901→  // --- Init ---
902→
903→  fetchSessions();
904→})();
