144→  function filterSessionByTime(session) {
145→    if (timeFilterDays === Infinity) return true;
146→    if (!session.last_active) return false;
147→    var cutoff = Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
148→    return new Date(session.last_active).getTime() >= cutoff;
149→  }
