461→  function switchTab(tabId) {
462→    if (!terminals[tabId]) return;
463→    if (activeTabId && terminals[activeTabId]) {
464→      terminals[activeTabId].container.classList.remove("active");
465→    }
466→    activeTabId = tabId;
467→    terminals[tabId].container.classList.add("active");
468→    terminals[tabId].fitAddon.fit();
469→    terminals[tabId].term.focus();
470→    renderTabs();
471→  }
472→
473→  function closeTab(tabId) {
474→    var tab = terminals[tabId];
475→    if (!tab) return;
476→    tab.ws.close();
477→    tab.term.dispose();
478→    tab.container.remove();
479→    delete terminals[tabId];
480→
481→    if (activeTabId === tabId) {
482→      var remaining = Object.keys(terminals);
483→      if (remaining.length > 0) {
484→        switchTab(remaining[remaining.length - 1]);
485→      } else {
486→        activeTabId = null;
487→        $terminalPanel.classList.add("hidden");
488→        document.body.classList.remove("terminal-open");
489→        window.removeEventListener("resize", handleTerminalResize);
490→        resizeListenerAttached = false;
491→      }
492→    }
493→    renderTabs();
494→  }
