496→  function createTerminalTab(title, wsParams, sessionId) {
497→    var tabId = generateTabId();
498→
499→    var container = document.createElement("div");
500→    container.className = "terminal-tab-container";
501→    $terminalContainer.appendChild(container);
502→
503→    var term = new Terminal({
504→      fontFamily: '"JetBrains Mono", "SF Mono", monospace',
505→      fontSize: 13,
506→      theme: {
507→        background: "#111111",
508→        foreground: "#FAFAFA",
509→        cursor: "#FF4D00",
510→      },
511→      cursorBlink: true,
512→    });
513→
514→    var fitAddon = new FitAddon.FitAddon();
515→    term.loadAddon(fitAddon);
516→    term.loadAddon(new WebLinksAddon.WebLinksAddon());
517→
518→    term.open(container);
519→
520→    var tabData = {
521→      id: tabId,
522→      term: term,
523→      ws: null,
524→      fitAddon: fitAddon,
525→      container: container,
526→      title: title,
527→      ended: false,
528→      sessionId: sessionId,
529→    };
530→    terminals[tabId] = tabData;
531→
532→    $terminalPanel.classList.remove("hidden");
533→    document.body.classList.add("terminal-open");
534→
535→    // Hide previous active tab, show this one
536→    if (activeTabId && terminals[activeTabId]) {
537→      terminals[activeTabId].container.classList.remove("active");
538→    }
539→    activeTabId = tabId;
540→    container.classList.add("active");
541→    fitAddon.fit();
542→
543→    var params = new URLSearchParams(wsParams);
544→    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
545→    var wsUrl = wsProtocol + "//" + location.host + "/ws/terminal?" + params.toString();
546→    var ws = new WebSocket(wsUrl);
547→    tabData.ws = ws;
548→
549→    ws.onopen = function () {
550→      ws.send(JSON.stringify({ type: "resize", cols: term.cols, rows: term.rows }));
551→      term.focus();
552→    };
553→
554→    ws.onmessage = function (evt) {
555→      term.write(evt.data);
556→    };
557→
558→    ws.onclose = function () {
559→      term.write("\r\n\x1b[90m[session ended]\x1b[0m\r\n");
560→      tabData.ended = true;
561→      renderTabs();
562→    };
563→
564→    term.onData(function (data) {
565→      if (ws.readyState === WebSocket.OPEN) ws.send(data);
566→    });
567→
568→    term.onResize(function (size) {
569→      if (ws.readyState === WebSocket.OPEN) {
570→        ws.send(JSON.stringify({ type: "resize", cols: size.cols, rows: size.rows }));
571→      }
572→    });
573→
574→    if (!resizeListenerAttached) {
575→      window.addEventListener("resize", handleTerminalResize);
576→      resizeListenerAttached = true;
577→    }
578→
579→    renderTabs();
580→    return tabId;
581→  }
